@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@if (Label is not null && !InsideFormField)
{
    <label class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

@if (Orientation == "Vertical")
{
    <div class="@VerticalCssClass" data-orientation="@OrientationData" data-disabled="@DisabledData" @attributes="AdditionalAttributes">
        <div class="relative flex h-full flex-col items-center">
            @if (Marks is not null || ShowTicks)
            {
                <div class="absolute start-6 top-0 flex h-full flex-col justify-between">
                    @foreach (var mark in GetTickValues())
                    {
                        var pos = GetPercent(mark);
                        <span class="text-xs text-muted-foreground whitespace-nowrap" style="position: absolute; top: @(pos)%; transform: translateY(-50%);">@FormatValue(mark)</span>
                    }
                </div>
            }
            <div class="relative h-full w-2 rounded-[var(--radius)] @(EffectiveInvalid ? "bg-destructive/20" : "bg-primary/20")" data-orientation="@OrientationData" data-disabled="@DisabledData">
                <div class="absolute bottom-0 w-full rounded-[var(--radius)] @(EffectiveInvalid ? "bg-destructive" : "bg-primary")" style="height: @(GetPercent(Value))%" data-orientation="@OrientationData" data-disabled="@DisabledData"></div>
                <input type="range" min="@Min" max="@Max" step="@Step" value="@Value" disabled="@Disabled"
                       name="@Name"
                       aria-label="@AriaLabel" aria-valuemin="@Min" aria-valuemax="@Max" aria-valuenow="@Value" aria-valuetext="@ValueText(Value)"
                       aria-required="@Required.ToString().ToLower()"
                       aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                       id="@FormFieldControlId" aria-describedby="@FormFieldDescribedBy"
                       data-orientation="@OrientationData" data-disabled="@DisabledData"
                       class="@VerticalInputClasses"
                       @oninput="OnInput"
                       @onpointerenter="() => _showTooltipThumb = true"
                       @onpointerleave="() => _showTooltipThumb = false"
                       @onfocus="() => _showTooltipThumb = true"
                       @onblur="() => _showTooltipThumb = false" />
            </div>
            @if (ShowTooltip && _showTooltipThumb)
            {
                <div class="absolute -start-10 rounded-md bg-popover px-2 py-1 text-xs text-popover-foreground shadow-md"
                     style="top: @(100 - GetPercent(Value))%; transform: translateY(-50%);">
                    @FormatValue(Value)
                </div>
            }
        </div>
    </div>
}
else if (IsRange)
{
    <div class="@CssClass" data-orientation="@OrientationData" data-disabled="@DisabledData" @attributes="AdditionalAttributes">
        <div class="relative w-full">
            <div class="absolute inset-0 flex items-center">
                <div class="h-2 w-full rounded-[var(--radius)] @(EffectiveInvalid ? "bg-destructive/20" : "bg-primary/20")" data-orientation="@OrientationData" data-disabled="@DisabledData"></div>
            </div>
            <div class="absolute inset-0 flex items-center" style="pointer-events: none;">
                <div class="h-2 rounded-[var(--radius)] @(EffectiveInvalid ? "bg-destructive" : "bg-primary")" style="margin-left: @(StartPercent)%; width: @(RangePercent)%;" data-orientation="@OrientationData" data-disabled="@DisabledData"></div>
            </div>
            <div class="relative flex items-center" style="pointer-events: none;">
                @* Both inputs overlay the full track, so hit-testing must live on
                   the THUMBS (pseudo-elements), not the inputs: with the whole
                   end input set to pointer-events:auto it sat on top across the
                   entire width and the start thumb could never be grabbed. *@
                <input type="range" min="@Min" max="@StartThumbMax" step="@Step" value="@Value" disabled="@Disabled"
                       name="@Name"
                       aria-label="@AriaLabel" aria-valuemin="@Min" aria-valuemax="@StartThumbMax" aria-valuenow="@Value" aria-valuetext="@ValueText(Value)"
                       aria-required="@Required.ToString().ToLower()"
                       aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                       id="@FormFieldControlId" aria-describedby="@FormFieldDescribedBy"
                       data-orientation="@OrientationData" data-disabled="@DisabledData"
                       class="@RangeInputClasses"
                       @oninput="OnStartInput" />
                <input type="range" min="@EndThumbMin" max="@Max" step="@Step" value="@ValueEnd" disabled="@Disabled"
                       aria-label="@EndAriaLabel" aria-valuemin="@EndThumbMin" aria-valuemax="@Max" aria-valuenow="@ValueEnd" aria-valuetext="@ValueText(ValueEnd)"
                       aria-required="@Required.ToString().ToLower()"
                       aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                       aria-describedby="@FormFieldDescribedBy"
                       data-orientation="@OrientationData" data-disabled="@DisabledData"
                       class="@RangeInputClasses"
                       style="position: absolute; left: 0; width: 100%;"
                       @oninput="OnEndInput" />
            </div>
            @if (Marks is not null || ShowTicks)
            {
                <div class="relative mt-2 w-full">
                    @foreach (var mark in GetTickValues())
                    {
                        var pos = GetPercent(mark);
                        <div class="absolute flex flex-col items-center" style="left: @(pos)%; transform: translateX(-50%);">
                            @if (ShowTicks)
                            {
                                <div class="h-1 w-px bg-muted-foreground/50"></div>
                            }
                            <span class="mt-1 text-xs text-muted-foreground">@FormatValue(mark)</span>
                        </div>
                    }
                </div>
            }
        </div>
    </div>
}
else
{
    <div class="@CssClass" data-orientation="@OrientationData" data-disabled="@DisabledData" @attributes="AdditionalAttributes">
        <div class="relative w-full">
            <div class="relative">
                <input type="range" min="@Min" max="@Max" step="@Step" value="@Value" disabled="@Disabled"
                       name="@Name"
                       aria-label="@AriaLabel" aria-valuemin="@Min" aria-valuemax="@Max" aria-valuenow="@Value" aria-valuetext="@ValueText(Value)"
                       aria-required="@Required.ToString().ToLower()"
                       aria-invalid="@EffectiveInvalid.ToString().ToLower()"
                       id="@FormFieldControlId" aria-describedby="@FormFieldDescribedBy"
                       data-orientation="@OrientationData" data-disabled="@DisabledData"
                       class="@InputClasses"
                       @oninput="OnInput"
                       @onpointerenter="() => _showTooltipThumb = true"
                       @onpointerleave="() => _showTooltipThumb = false"
                       @onfocus="() => _showTooltipThumb = true"
                       @onblur="() => _showTooltipThumb = false" />
                @if (ShowTooltip && _showTooltipThumb)
                {
                    <div class="absolute -top-8 rounded-md bg-popover px-2 py-1 text-xs text-popover-foreground shadow-md"
                         style="left: @(GetPercent(Value))%; transform: translateX(-50%);">
                        @FormatValue(Value)
                    </div>
                }
            </div>
            @if (Marks is not null || ShowTicks)
            {
                <div class="relative mt-1 w-full">
                    @foreach (var mark in GetTickValues())
                    {
                        var pos = GetPercent(mark);
                        <div class="absolute flex flex-col items-center" style="left: @(pos)%; transform: translateX(-50%);">
                            @if (ShowTicks)
                            {
                                <div class="h-1 w-px bg-muted-foreground/50"></div>
                            }
                            <span class="mt-1 text-xs text-muted-foreground">@FormatValue(mark)</span>
                        </div>
                    }
                </div>
            }
        </div>
    </div>
}

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive" role="alert" aria-live="polite">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground">@HelperText</p>
    }
}
</div>

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Adopt the FormField's generated id + describedby on the range <input> (the
    // focusable slider thumb) so the field's <Label For> click-focuses the slider and
    // aria-describedby points at the help/error text. Null outside a FormField.
    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Localized "(end)" suffix for the range slider's second thumb so screen
    // readers in non-English locales announce a meaningful label.
    private string? EndAriaLabel => string.IsNullOrEmpty(AriaLabel) ? null : $"{AriaLabel} ({L["Slider.End"]})";

    [Parameter] public double Value { get; set; }
    [Parameter] public EventCallback<double> ValueChanged { get; set; }
    [Parameter] public bool IsRange { get; set; }
    [Parameter] public double ValueEnd { get; set; }
    [Parameter] public EventCallback<double> ValueEndChanged { get; set; }
    /// <summary>
    /// Minimum permitted distance between the two range thumbs, expressed in
    /// <see cref="Step"/> units (so the absolute gap is <c>MinStepsBetweenThumbs * Step</c>).
    /// Mirrors Radix's <c>minStepsBetweenThumbs</c>. The default of <c>0</c> lets the
    /// thumbs meet but — unlike before — they can no longer cross past each other.
    /// Only meaningful when <see cref="IsRange"/> is true.
    /// </summary>
    [Parameter] public int MinStepsBetweenThumbs { get; set; }
    [Parameter] public double Min { get; set; } = 0;
    [Parameter] public double Max { get; set; } = 100;
    [Parameter] public double Step { get; set; } = 1;
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string Orientation { get; set; } = "Horizontal";
    /// <summary>
    /// Accessible name exposed via <c>aria-label</c> on the underlying range input.
    /// Required for WCAG compliance when the slider is not visually labelled by
    /// adjacent text connected via <c>for</c>/<c>htmlFor</c>. For range sliders
    /// (<see cref="IsRange"/>=true) the end handle's aria-label is automatically
    /// suffixed with "(end)".
    /// </summary>
    [Parameter] public string? AriaLabel { get; set; }
    [Parameter] public bool ShowTooltip { get; set; }
    [Parameter] public List<double>? Marks { get; set; }
    [Parameter] public bool ShowTicks { get; set; }
    [Parameter] public Func<double, string>? FormatTooltip { get; set; }

    /// <summary>
    /// Culture used for the default tooltip/mark value formatting. When null (default)
    /// falls back to <see cref="System.Globalization.CultureInfo.CurrentCulture"/>. Ignored
    /// when <see cref="FormatTooltip"/> is supplied.
    /// </summary>
    [Parameter] public System.Globalization.CultureInfo? Culture { get; set; }

    private System.Globalization.CultureInfo EffectiveCulture => Culture ?? System.Globalization.CultureInfo.CurrentCulture;

    // shadcn/Radix styling hooks: data-orientation ("horizontal"|"vertical") and
    // data-disabled (present when Disabled) on the root/track/range/thumb so consumers
    // can drive visuals with data-[orientation=vertical] / data-[disabled] selectors.
    private string OrientationData => string.Equals(Orientation, "Vertical", StringComparison.OrdinalIgnoreCase) ? "vertical" : "horizontal";
    private string? DisabledData => Disabled ? string.Empty : null;

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _showTooltipThumb;

    // A zero / negative / NaN / Infinite Step is meaningless for a slider: the
    // native control renders inert (step="0" snaps to no value), and it poisons
    // the tick + range-gap math (MinGap = MinStepsBetweenThumbs * Step, the native
    // step="@Step" attribute, and the percentage math). Mirror native/Radix
    // semantics by falling back to 1 for any non-positive or non-finite Step.
    // (Step > 0 is already false for NaN; the explicit IsFinite also rejects
    // +Infinity, which would otherwise pass the > 0 test.)
    protected override void OnParametersSet()
    {
        if (!(Step > 0) || double.IsInfinity(Step))
        {
            Step = 1;
        }
    }

    private string CssClass => Cx.Merge("relative flex w-full touch-none select-none items-center", Class);
    private string VerticalCssClass => Cx.Merge("relative flex h-full min-h-[200px] touch-none select-none justify-center", Class);

    // appearance-none strips the native focus outline, so add an explicit
    // focus-visible ring (WCAG 2.4.7) — without it a keyboard user can't see which
    // slider, or which range thumb, is focused. The rounded ring follows the track.
    private const string FocusRing = "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background";

    private string InputClasses => $"w-full h-2 cursor-pointer appearance-none rounded-[var(--radius)] {(EffectiveInvalid ? "bg-destructive/20 accent-destructive" : "bg-primary/20 accent-primary")} {FocusRing} disabled:cursor-not-allowed disabled:opacity-50";

    private string VerticalInputClasses => $"absolute inset-0 h-full w-full cursor-pointer appearance-none rounded-[var(--radius)] bg-transparent {(EffectiveInvalid ? "accent-destructive" : "accent-primary")} {FocusRing} disabled:cursor-not-allowed disabled:opacity-50 [writing-mode:vertical-lr] [direction:rtl]";

    private static readonly string RangeInputClasses = $"w-full h-2 cursor-pointer appearance-none rounded-[var(--radius)] bg-transparent accent-primary {FocusRing} disabled:cursor-not-allowed disabled:opacity-50 pointer-events-none [&::-webkit-slider-thumb]:pointer-events-auto [&::-moz-range-thumb]:pointer-events-auto";

    private double StartPercent => Max > Min ? ((Math.Min(Value, ValueEnd) - Min) / (Max - Min)) * 100 : 0;
    private double RangePercent => Max > Min ? ((Math.Abs(ValueEnd - Value)) / (Max - Min)) * 100 : 0;

    private double GetPercent(double value) => Max > Min ? ((value - Min) / (Max - Min)) * 100 : 0;

    private string FormatValue(double value) => FormatTooltip is not null ? FormatTooltip(value) : value.ToString("G", EffectiveCulture);

    // aria-valuetext: only when a custom formatter is supplied does the numeric
    // aria-valuenow need a human-friendly text alternative (e.g. "$50", a date, a
    // category label). For a plain numeric slider aria-valuenow alone is correct, so
    // this returns null and the attribute is omitted (WAI-ARIA slider guidance).
    private string? ValueText(double value) => FormatTooltip is not null ? FormatValue(value) : null;

    private List<double> GetTickValues()
    {
        if (Marks is not null) return Marks;
        return new List<double> { Min, Max };
    }

    private async Task OnInput(ChangeEventArgs e)
    {
        if (double.TryParse(e.Value?.ToString(), System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out var newValue))
        {
            Value = newValue;
            await ValueChanged.InvokeAsync(Value);
        }
    }

    // Absolute minimum gap the two thumbs must keep, in value units. Negative
    // MinStepsBetweenThumbs is treated as 0 (thumbs may meet but not cross).
    private double MinGap => Math.Max(0, MinStepsBetweenThumbs) * Step;

    // The REACHABLE bounds for each range thumb (the C# clamp stops the start thumb
    // at ValueEnd-MinGap and the end thumb at Value+MinGap). These drive BOTH the
    // aria-valuemin/max (so a screen reader announces only the reachable range) AND
    // the native input min/max (so the native control itself stops at the reachable
    // bound instead of letting the thumb drag into the forbidden zone and snap back —
    // keeping native min/max in agreement with ARIA). WAI-ARIA multi-thumb slider.
    private double StartThumbMax => Math.Max(Min, ValueEnd - MinGap);
    private double EndThumbMin => Math.Min(Max, Value + MinGap);

    private async Task OnStartInput(ChangeEventArgs e)
    {
        if (double.TryParse(e.Value?.ToString(), System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out var newValue))
        {
            // Clamp so the start thumb can't cross (or come within MinGap of) the
            // end thumb — previously the two inputs moved independently and could
            // swap order, which scrambled the filled range.
            var ceiling = ValueEnd - MinGap;
            if (newValue > ceiling) newValue = ceiling;
            if (newValue < Min) newValue = Min;

            // The clamped value equals the model: the user dragged into the
            // forbidden zone but the result snaps back to where we already are.
            // The native <input>'s own value HAS moved to the raw dragged spot,
            // so a bare return would leave the thumb desynced in the forbidden
            // zone. Force a re-render so Blazor re-writes value="@Value" onto the
            // DOM input and the thumb snaps back. (Single-thumb OnInput never
            // early-returns, so it isn't affected.)
            if (newValue == Value) { StateHasChanged(); return; }
            Value = newValue;
            await ValueChanged.InvokeAsync(Value);
        }
    }

    private async Task OnEndInput(ChangeEventArgs e)
    {
        if (double.TryParse(e.Value?.ToString(), System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out var newValue))
        {
            // Symmetric clamp: the end thumb can't drop below start + MinGap.
            var floor = Value + MinGap;
            if (newValue < floor) newValue = floor;
            if (newValue > Max) newValue = Max;

            if (newValue == ValueEnd) return;
            ValueEnd = newValue;
            await ValueEndChanged.InvokeAsync(ValueEnd);
        }
    }
}
